-- Siete reservas por usuario demo: tres realizadas, dos futuras y dos canceladas.
WITH demo AS (
  SELECT u.id AS usuario_id,
         ROW_NUMBER() OVER (ORDER BY u.email) AS idx
  FROM usuarios u
  WHERE u.email LIKE '%@viajesjmj.test' AND u.role = 'USER'
), reserva_base AS (
  SELECT d.usuario_id,
         d.idx,
         gs.r,
         CASE gs.r
           WHEN 1 THEN 2
           WHEN 2 THEN 1
           WHEN 3 THEN 4
           WHEN 4 THEN 2
           WHEN 5 THEN 5
           WHEN 6 THEN 3
           ELSE 6
         END AS huespedes,
         CASE (gs.r % 3) WHEN 1 THEN 'AVION' WHEN 2 THEN 'TREN' ELSE 'BARCO' END AS transporte,
         CASE
           WHEN gs.r IN (1, 2, 3) THEN 'COMPLETADA'
           WHEN gs.r IN (6, 7) THEN 'CANCELADA'
           ELSE 'CONFIRMADA'
         END AS estado,
         CASE gs.r
           WHEN 1 THEN (CURRENT_DATE - ((180 + d.idx) || ' days')::interval)::date
           WHEN 2 THEN (CURRENT_DATE - ((120 + d.idx) || ' days')::interval)::date
           WHEN 3 THEN (CURRENT_DATE - ((70 + d.idx) || ' days')::interval)::date
           WHEN 4 THEN (CURRENT_DATE + ((20 + d.idx) || ' days')::interval)::date
           WHEN 5 THEN (CURRENT_DATE + ((55 + d.idx) || ' days')::interval)::date
           WHEN 6 THEN (CURRENT_DATE - ((40 + d.idx) || ' days')::interval)::date
           ELSE (CURRENT_DATE + ((85 + d.idx) || ' days')::interval)::date
         END AS fecha_inicio
  FROM demo d
  CROSS JOIN generate_series(1, 7) AS gs(r)
), reservas_preparadas AS (
  SELECT rb.*, h.id AS habitacion_id, h.precio_por_noche
  FROM reserva_base rb
  JOIN LATERAL (
    SELECT h.id, h.precio_por_noche
    FROM habitacion h
    WHERE h.capacidad >= rb.huespedes
      AND (
        rb.huespedes = 1
        OR (rb.huespedes = 2 AND (LOWER(h.tipo) LIKE '%doble%' OR LOWER(h.tipo) LIKE '%suite%' OR LOWER(h.tipo) LIKE '%grupal%' OR LOWER(h.tipo) LIKE '%standard%' OR LOWER(h.tipo) LIKE '%estandar%' OR LOWER(h.tipo) LIKE '%deluxe%'))
        OR (rb.huespedes BETWEEN 3 AND 4 AND (LOWER(h.tipo) LIKE '%suite%' OR LOWER(h.tipo) LIKE '%grupal%'))
        OR (rb.huespedes BETWEEN 5 AND 8 AND LOWER(h.tipo) LIKE '%grupal%')
      )
    ORDER BY ((h.id + rb.idx * 17 + rb.r * 31) % 1000)
    LIMIT 1
  ) h ON true
)
SELECT transporte,
       habitacion_id,
       usuario_id,
       fecha_inicio,
       fecha_inicio + ((3 + (r % 4)) || ' days')::interval,
       huespedes,
       ROUND(((precio_por_noche * (3 + (r % 4)) * huespedes) + CASE transporte WHEN 'AVION' THEN 180 WHEN 'TREN' THEN 70 ELSE 120 END)::numeric, 2),
       estado,
       NOW() - ((idx + r) || ' days')::interval
FROM reservas_preparadas;

-- Cuatro reseñas por alojamiento, siempre hechas por usuarios demo.
WITH demo AS (
  SELECT u.id AS usuario_id,
         ROW_NUMBER() OVER (ORDER BY u.email) AS idx,
         COUNT(*) OVER () AS total_demo
  FROM usuarios u
  WHERE u.email LIKE '%@viajesjmj.test' AND u.role = 'USER'
), hoteles AS (
  SELECT a.id AS alojamiento_id,
         ROW_NUMBER() OVER (ORDER BY a.id) AS hotel_idx
  FROM alojamientos a
), review_target AS (
  SELECT h.alojamiento_id,
         h.hotel_idx,
         gs.r,
         d.usuario_id
  FROM hoteles h
  CROSS JOIN generate_series(1, 4) AS gs(r)
  JOIN demo d
    ON d.idx = (((h.hotel_idx + gs.r * 7 - 1) % d.total_demo) + 1)
)
SELECT usuario_id,
       alojamiento_id,
       CASE ((hotel_idx + r) % 8)
         WHEN 0 THEN 3
         WHEN 1 THEN 4
         WHEN 2 THEN 4
         WHEN 3 THEN 5
         WHEN 4 THEN 4
         WHEN 5 THEN 5
         WHEN 6 THEN 3
         ELSE 4
       END,
       CASE ((hotel_idx + r) % 8)
         WHEN 0 THEN 'Habitacion comoda, buena ubicacion y personal atento durante toda la estancia.'
         WHEN 1 THEN 'El hotel estaba limpio y bien comunicado; repetiria para una escapada corta.'
         WHEN 2 THEN 'Buena relacion calidad-precio, desayuno correcto y check-in rapido.'
         WHEN 3 THEN 'La ubicacion fue lo mejor. La habitacion era sencilla, pero suficiente.'
         WHEN 4 THEN 'Instalaciones cuidadas y ambiente tranquilo para descansar despues de visitar la ciudad.'
         WHEN 5 THEN 'Personal amable, camas comodas y zonas comunes muy cuidadas.'
         WHEN 6 THEN 'Cumplio bien para el viaje: correcto, limpio y cerca de las visitas principales.'
         ELSE 'Experiencia positiva en general, con servicio amable y descanso agradable.'
       END,
       NOW() - ((hotel_idx % 60 + r * 3) || ' days')::interval
FROM review_target;

