UPDATE destinos d
SET nombre = g.nombre,
    pais = g.pais,
    continente_id = g.continente_id
FROM destino_geo g
WHERE d.id = g.id;

UPDATE alojamientos a
SET nombre = CASE
      WHEN a.nombre LIKE 'Hotel Central %' THEN 'Hotel Central ' || d.nombre
      WHEN a.nombre LIKE 'Hotel Grand Palace %' THEN 'Hotel Grand Palace ' || d.nombre
      WHEN a.nombre LIKE 'Hotel Boutique %' THEN 'Hotel Boutique ' || d.nombre
      WHEN a.nombre LIKE 'Hotel Vista %' THEN 'Hotel Vista ' || d.nombre
      ELSE a.nombre
    END,
    ciudad = d.nombre,
    pais = d.pais
FROM destinos d
WHERE a.destino_id = d.id
  AND (
    a.nombre IS DISTINCT FROM CASE
      WHEN a.nombre LIKE 'Hotel Central %' THEN 'Hotel Central ' || d.nombre
      WHEN a.nombre LIKE 'Hotel Grand Palace %' THEN 'Hotel Grand Palace ' || d.nombre
      WHEN a.nombre LIKE 'Hotel Boutique %' THEN 'Hotel Boutique ' || d.nombre
      WHEN a.nombre LIKE 'Hotel Vista %' THEN 'Hotel Vista ' || d.nombre
      ELSE a.nombre
    END
    OR a.ciudad IS DISTINCT FROM d.nombre
    OR a.pais IS DISTINCT FROM d.pais
  );
